{"npsn":"40500153","name":"SMP NEGERI 1 PAGUYAMAN","address":"Dusun Oloa","village":"Sosial","status":"Negeri","jenjang":"SMP","district":"Paguyaman","regencyBpsCode":"7502","regencyName":"Kabupaten Boalemo","provinceName":"Gorontalo","school_id":"88ab86be-ab69-4808-9e20-f34a466dd9ef","user_id":"701fbef5-5c3b-4619-9991-021516851c2a","password_hash":"$2b$04$Is2bvsQLIjZyTJMas4Oxh.SrPkYF7aRVkpfSS.PJ9vn4RSA9v6xly"},
